async function main() {
  await client.connect();
  console.log('Connected to Supabase');

  // Get current max IDs
  const maxProblem = await client.query('SELECT COALESCE(MAX(id), 0) as max_id FROM problems');
  const maxTestCase = await client.query('SELECT COALESCE(MAX(id), 0) as max_id FROM test_cases');
  let problemId = Math.max(maxProblem.rows[0].max_id + 1, 10001);
  let testCaseId = Math.max(maxTestCase.rows[0].max_id + 1, 100001);

  console.log(`Starting problem ID: ${problemId}, test case ID: ${testCaseId}`);
  console.log(`Total problems to insert: ${problems.length}`);

  let inserted = 0;
  let skipped = 0;

  for (const p of problems) {
    // Check if problem with same title already exists
    const exists = await client.query('SELECT id FROM problems WHERE title = $1', [p.title]);
    if (exists.rows.length > 0) {
      skipped++;
      continue;
    }

    await client.query(
      `INSERT INTO problems (id, title, description, difficulty, input_format, output_format, constraints, sample_input, sample_output, category, total_submissions, accepted_submissions, time_limit_ms, memory_limit_mb, created_at)
       VALUES ($1, $2, $3, 'HARD', $4, $5, $6, $7, $8, $9, 0, 0, 3000, 512, NOW())`,
      [problemId, p.title, p.desc, p.inp, p.out, p.constraints, p.tc[0][0], p.tc[0][1], p.cat]
    );

    for (let j = 0; j < p.tc.length; j++) {
      await client.query(
        `INSERT INTO test_cases (id, problem_id, input, expected_output, is_sample, order_index)
         VALUES ($1, $2, $3, $4, $5, $6)`,
        [testCaseId++, problemId, p.tc[j][0], p.tc[j][1], j === 0, j]
      );
    }

    problemId++;
    inserted++;
    if (inserted % 25 === 0) console.log(`Inserted ${inserted} problems...`);
  }

  // Update sequences
  await client.query("SELECT setval('problems_id_seq', (SELECT COALESCE(MAX(id), 0) FROM problems))");
  await client.query("SELECT setval('test_cases_id_seq', (SELECT COALESCE(MAX(id), 0) FROM test_cases))");

  // Count totals
  const totalProblems = await client.query('SELECT COUNT(*) as cnt FROM problems');
  const hardProblems = await client.query("SELECT COUNT(*) as cnt FROM problems WHERE difficulty = 'HARD'");
  const totalTestCases = await client.query('SELECT COUNT(*) as cnt FROM test_cases');

  console.log(`\nDone! Inserted: ${inserted}, Skipped (duplicates): ${skipped}`);
  console.log(`Total problems in DB: ${totalProblems.rows[0].cnt}`);
  console.log(`Total HARD problems: ${hardProblems.rows[0].cnt}`);
  console.log(`Total test cases: ${totalTestCases.rows[0].cnt}`);

  await client.end();
}

main().catch(err => { console.error(err); process.exit(1); });
